<template>
  <div class="q-pa-md">
    <q-table
      :loading="this.rows.length==0"
     :dense="$q.screen.lt.md"
      :title="model"
      :rows="rows"
      :columns="columns"
      :visible-columns="visibleColumns"
      row-key="key"
      binary-state-sort
      :fullScreen="true"
      :filter="filter"
    >    
    <template v-slot:top-right>
        <q-btn
          color="primary"
          icon-right="archive"
          label="Export to csv"
          no-caps
          @click="exportTable"
        />
      </template>
      <template v-slot:top-left>
        <q-input borderless dense debounce="300" v-model="filter" placeholder="Search">
          <template v-slot:append>
            <q-icon name="search" />
          </template>
        </q-input>
      </template>
    <template v-slot:body="props">
      <q-tr :props="props">
        <q-td v-for="col in props.cols" :key="col.name" :props="props">
          <template v-if="col.name!='actions'">
          <template v-if="col.foreign">
              <template v-if="props.row[col.name]===null||props.row[col.name]===undefined">
                hej
              </template>
              <template v-else-if="props.row[col.name].length!==undefined">
              <q-chip-group class="truncate">
              <q-chip
                v-for="(item, index) in props.row[col.name]"
                :key="item"
                :closable="true"
                removable
                @remove="removeItem(props.row.key,col.name,index)"
              >
                {{ item.name }}
              </q-chip>
            </q-chip-group>
            </template>
            <template v-else>

              <p v-if="col.modeltype=='User'">{{ props.row[col.name].displayName }}</p>
              <p v-else>{{ props.row[col.name] }}</p>
            </template>
            <!--<ForeignKey :index="0" :key="props.row.key" :selected="props.row[col.name]" :model="col.name" @childEvent="onChildEvent" />-->
          </template>
          <template v-else-if="default_modeltypes.includes(col.modeltype.toLowerCase())">
            {{ props.row[col.name] }}
            <q-popup-edit v-model="props.row[col.name]" v-slot="scope">
              <q-input v-model="scope.value" dense autofocus counter  @keyup.enter="scope.set" />
            </q-popup-edit>
          </template>
          <template v-else>
            <ModelCell :props="{src:props.row[col.name],index:props.row.key,col:col.name}" :component="'Admin'+col.modeltype"  @update="colUpdate"/>
          </template>
          </template>
          <template v-if="col.name=='actions'">
              <q-col>
                <q-btn color="red" @click="deleteItem(props.row)">
                  <q-icon name="delete" />
                </q-btn>
              </q-col>
              <q-col>
                <q-btn color="yellow"  @click="updateItem(props.row.key,props.row)">
                  <q-icon name="sync" />
                </q-btn>
              </q-col>
          </template>
        </q-td>
      </q-tr>
    </template>
      <template v-slot:no-data="{ icon, message, filter }">
        <div class="full-width row flex-center text-accent q-gutter-sm">
          <q-icon size="2em" name="sentiment_dissatisfied" />
          <span>
            Well this is sad... {{ message }}
          </span>
          <q-icon size="2em" :name="filter ? 'filter_b_and_w' : icon" />
        </div>
      </template>
    </q-table>
  </div>
</template>

<script>
import { ref } from 'vue'
import { exportFile, useQuasar } from 'quasar'
import DataModelMixin from './DataModelMixin'
import ForeignKey from './ForeignKey.vue'
import ModelCell from './ModelCell.vue'
export default {
  name:'ModelTable',
  mixins: [DataModelMixin],
  components:{
    ForeignKey,
    ModelCell
  },
  data () {
    return {
      rows:[],
      filter:'',
      default_modeltypes:[
        "string",
        "number",
        // "boolean",
        //"interface"
      ]
    }
  },
  computed: {
    columns(){
      var cols= this.model.toTable()
      cols.push({name:'actions',label:'Actions',field:'actions',sortable:false})
      return cols
    },
    visibleColumns(){
      return this.columns.filter(col => !col.hide).map(col => col.name)
    }
  },
  methods:{
    async deleteItem(key){
      if(this.service.model=="User"){
        await this.adminService.deleteUser(key.key).then((res) => {
          console.log(res)
          this.rows= this.rows.filter(row => {
            return row.key!=key
          })
        })
        }else if(this.service.model=="Products"){
          this.service.delete(key).then((res) => {
            console.log(res)
            this.rows= this.rows.filter(row => {
              return row.key!=key
            })
          })
      }else{
        this.service.delete(key.key).then((res) => {
          console.log(res)
          this.rows= this.rows.filter(row => {
            return row.key!=key
          })
        })
      }

    },
    updateItem(key,row){
      if(this.service.model=="User"){
        this.adminService.updateUser(key,row).then((res) => {
          console.log(key,typeof row)
          console.log(res)
        })
      }else{
        console.log(key,row)
        this.service.update(key,row.toObject()).then((res) => {
          console.log(key,Object.assign({}, row))
          console.log(res)
        })
      }
    },
    onChildEvent(val, key){
      console.log('onChildEvent',val, key)
      this.rows= this.rows.map(row => {
        if(row.key==key){
          row = val
        }
        return row
      })
    },
    removeItem(key,col,index){
      console.log('removeItem',key,index)
      this.rows= this.rows.filter(row => {
        if(row.key==key){
          row[col].splice(index,1)
        }
        return row
      })
    },
    colUpdate(val){
      console.log('colUpdate',val)
      this.rows= this.rows.map(row => {
        if(row.key==val.index){
          row[val.col] = val.value
        }
        return row
      })
    },
    wrapCsvValue (val, formatFn, row) {
      let formatted = formatFn !== void 0
        ? formatFn(val, row)
        : val
      
      if(typeof formatted==='object'){
        formatted=JSON.stringify(formatted)
      }

      formatted = formatted === void 0 || formatted === null
        ? ''
        : String(formatted)

      formatted = formatted.split('"').join('""')
      /**
      * Excel accepts \n and \r in strings, but some other CSV parsers do not
      * Uncomment the next two lines to escape new lines
      */
      // .split('\n').join('\\n')
      // .split('\r').join('\\r')

      return `"${formatted}"`
  },
      exportTable () {
        // naive encoding to csv format
        const content = [this.columns.map(col => this.wrapCsvValue(col.label))].concat(
          this.rows.map(row => this.columns.map(col => this.wrapCsvValue(
            typeof col.field === 'function'
              ? col.field(row)
              : row[ col.field === void 0 ? col.name : col.field ],
            col.format,
            row
          )).join(','))
        ).join('\r\n')

        const status = exportFile(
          'table-export.csv',
          content,
          'text/csv'
        )

        if (status !== true) {
          $q.notify({
            message: 'Browser denied file download...',
            color: 'negative',
            icon: 'warning'
          })
        }
      }
  },
  async created(){
    console.log(this.model)
      if(this.service.model=="User"){
        this.adminService.getUsers().then((users) => {
          var rows=users.data.map((user) => {
            user.key=user.uid
            return new this.model.constructor(...Object.values(user)).toObject()
          })
          console.log(rows)
          this.rows = ref(users.data)
        })
        
      }else{      
        // await this.service.db.on('value', (snapshot) => {
        //     const data = snapshot.val();
        //     if (!data) {
        //       return;
        //     }
        //     var rows = Object.entries(data).map(([key, value]) => {
        //       return { key, ...value };
        //     });
        //     this.rows = ref(rows)
        // });
        console.log(this.model.toObject())
         await this.service.loadAllToModel()
          .then((rows) => {
            console.log(rows)
            rows=rows.map((row) => {
              console.log(row)
              return row
            })
            console.log(rows)
            this.rows = ref(rows)
          })
    }
  }

}
</script>
<style lang="sass" scoped>
.truncate-chip-labels > .q-chip
  max-width: 140px
</style>
